import android.content.Context;
import android.content.Intent;
import android.os.Bundle;
import android.util.Log;
import android.view.View;
import android.widget.Button;
import android.widget.EditText;
import android.widget.Toast;

import androidx.appcompat.app.AppCompatActivity;

import com.google.gson.Gson;
import com.google.gson.reflect.TypeToken;

import java.io.BufferedReader;
import java.io.BufferedWriter;
import java.io.FileInputStream;
import java.io.FileOutputStream;
import java.io.IOException;
import java.io.InputStreamReader;
import java.io.OutputStreamWriter;
import java.lang.reflect.Type;
import java.security.MessageDigest;
import java.security.NoSuchAlgorithmException;
import java.util.ArrayList;
import java.util.List;

public class LoginActivity extends AppCompatActivity {

    private EditText emailEditText, passwordEditText;
    private Button loginButton;
    private SharedPreferences sharedPreferences;

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_login);

        emailEditText = findViewById(R.id.email_edit_text);
        passwordEditText = findViewById(R.id.password_edit_text);
        loginButton = findViewById(R.id.login_button);

        sharedPreferences = getSharedPreferences("login_credentials", MODE_PRIVATE);

        loginButton.setOnClickListener(new View.OnClickListener() {
            @Override
            public void onClick(View v) {
                String email = emailEditText.getText().toString();
                String password = passwordEditText.getText().toString();

                if (email.isEmpty() || password.isEmpty()) {
                    Toast.makeText(LoginActivity.this, "Please enter both email and password", Toast.LENGTH_SHORT).show();
                    return;
                }

                login(email, password);
            }
        });
    }

    private void login(String email, String password) {
        // Simulate login process
        if (email.equals("test@example.com") && password.equals("password")) {
            saveCredentials(email, getAuthToken());
            Intent intent = new Intent(LoginActivity.this, DashboardActivity.class);
            startActivity(intent);
            finish();
        } else {
            Toast.makeText(this, "Invalid email or password", Toast.LENGTH_SHORT).show();
        }
    }

    private String getAuthToken() {
        // Simulate getting auth token from server
        return "auth_token";
    }

    private void saveCredentials(String email, String authToken) {
        SharedPreferences.Editor editor = sharedPreferences.edit();

        Gson gson = new Gson();
        Type type = new TypeToken<List<Credentials>>(){}.getType();
        List<Credentials> credentialsList = new ArrayList<>();

        try (FileInputStream fis = openFileInput("credentials.txt")) {
            BufferedReader br = new BufferedReader(new InputStreamReader(fis));
            String line;
            while ((line = br.readLine()) != null) {
                Credentials credentials = gson.fromJson(line, Credentials.class);
                credentialsList.add(credentials);
            }
        } catch (IOException e) {
            Log.e("LoginActivity", "Error reading credentials file", e);
        }

        for (Credentials credentials : credentialsList) {
            if (credentials.getEmail().equals(email)) {
                editor.putString("email", email);
                editor.putString("auth_token", authToken);
                break;
            }
        }

        if (!editor.commit()) {
            Log.e("LoginActivity", "Error saving credentials");
        }

        try (FileOutputStream fos = openFileOutput("credentials.txt", MODE_PRIVATE)) {
            BufferedWriter bw = new BufferedWriter(new OutputStreamWriter(fos));
            for (Credentials credentials : credentialsList) {
                bw.write(gson.toJson(credentials));
                bw.newLine();
            }
        } catch (IOException e) {
            Log.e("LoginActivity", "Error writing to credentials file", e);
        }

        Toast.makeText(this, "Logged in successfully", Toast.LENGTH_SHORT).show();
    }

    private String hashPassword(String password) {
        try {
            MessageDigest md = MessageDigest.getInstance("SHA-256");
            byte[] bytes = md.digest(password.getBytes());
            StringBuilder sb = new StringBuilder();
            for (byte b : bytes) {
                sb.append(String.format("%02x", b));
            }
            return sb.toString();
        } catch (NoSuchAlgorithmException e) {
            Log.e("LoginActivity", "Error hashing password", e);
            return "";
        }
    }

    private class Credentials {
        String email;
        String password;

        public Credentials(String email, String password) {
            this.email = email;
            this.password = hashPassword(password);
        }

        public String getEmail() {
            return email;
        }

        public void setEmail(String email) {
            this.email = email;
        }
    }
}